int countComponents(unordered_map<int, vector<int>>& graph,
                    vector<int>& nodes) {
    unordered_set<int> visited;
    int count = 0;
    for (int node : nodes) {
        if (!visited.count(node)) {
            dfs(graph, node, visited);
            count++;
        }
    }
    return count;
}

